169→    },
170→    [message.id, onBlocksChange],
171→  );
172→
173→  const handleDuplicateBlock = useCallback(
174→    (blockIndex: number) => {
175→      if (!onBlocksChange) return;
176→      const updatedBlocks = [...blocksRef.current];
177→      const original = updatedBlocks[blockIndex];
178→      if (!original) return;
179→      const copy = { ...original } as Block;
180→      updatedBlocks.splice(blockIndex + 1, 0, copy);
