236→            <button
237→              type="button"
238→              className="text-red-600 hover:text-red-800 underline"
239→              onClick={(e) => {
240→                e.stopPropagation();
241→                onRestore();
242→              }}
243→            >
244→              Wiederherstellen
245→            </button>
246→          )}
247→        </div>
248→      )}
249→      <div className="mb-4 flex items-center gap-3 text-xs uppercase tracking-[0.18em] text-muted-foreground">
250→        <span>{getRoleLabel(message.role)}</span>
