253→          <span className="ml-auto flex items-center gap-1">
254→            {onCopyMessage && (
255→              <button
256→                type="button"
257→                className="rounded-lg p-1.5 text-muted-foreground hover:bg-secondary/50 hover:text-foreground transition-colors"
