279→          const blockText = blockToPlainText(block);
280→          const blockEffects =
281→            effectsMap.get(`${message.id}:${blockIndex}`) ?? [];
282→          const isSelected =
283→            selectedBlock?.messageId === message.id &&
284→            selectedBlock.blockIndex === blockIndex;
285→          const isHighlighted = highlightedBlocks.has(
286→            `${message.id}:${blockIndex}`,
287→          );
288→          const emitSelection = (
289→            anchor: ViewportAnchor,
290→            selectedText: string,
291→          ) => {
292→            lastSelectionInteractionAt.current = Date.now();
293→
294→            onSelectBlock(
295→              {
296→                blockIndex,
297→                blockType: block.type,
298→                messageId: message.id,
299→                messageIndex,
300→                messageRole: message.role,
301→                selectedText,
302→                textQuote: truncateSelectionText(selectedText),
303→              },
304→              anchor,
305→            );
306→          };
307→
308→          const inserts = collectInserts(blockEffects);
309→
310→          return (
311→            // biome-ignore lint/suspicious/noArrayIndexKey: block identity is message.id + blockIndex
312→            <React.Fragment key={`${message.id}-${blockIndex}`}>
313→              {inserts.insertBefore === "hr" && (
314→                <hr className="border-border/40" />
315→              )}
316→              {inserts.insertBefore === "spacer" && <div className="h-6" />}
317→              {/* biome-ignore lint/a11y/noStaticElementInteractions: hover tracking for block toolbar */}
318→              <div
319→                className="relative"
320→                onMouseEnter={() => handleBlockMouseEnter(blockIndex)}
321→                onMouseLeave={handleBlockMouseLeave}
322→              >
323→                {editMode &&
324→                  onBlocksChange &&
325→                  hoveredBlockIndex === blockIndex && (
326→                    <BlockToolbar
327→                      block={block}
328→                      blockIndex={blockIndex}
329→                      totalBlocks={message.blocks.length}
330→                      onDelete={handleDeleteBlock}
331→                      onDuplicate={handleDuplicateBlock}
332→                      onInsertBlock={handleInsertBlock}
333→                      onMenuOpenChange={handleToolbarMenuOpenChange}
334→                      onMoveUp={handleMoveUp}
335→                      onMoveDown={handleMoveDown}
336→                    />
337→                  )}
338→                {/* biome-ignore lint/a11y/useKeyWithClickEvents: block selection is pointer-only by design */}
339→                {/* biome-ignore lint/a11y/noStaticElementInteractions: block selection uses onPointerUp + onClick */}
340→                <div
341→                  data-testid={`reader-block-${message.id}-${blockIndex}`}
342→                  className={getReaderBlockClassName({
343→                    adjustModeEnabled,
344→                    effects: blockEffects,
345→                    isHighlighted,
346→                    isSelected,
347→                  })}
348→                  style={getReaderBlockStyle(blockEffects)}
349→                  data-selected={isSelected ? "true" : "false"}
350→                  onPointerUp={(event) => {
351→                    if (!adjustModeEnabled) {
352→                      return;
353→                    }
354→
355→                    const selection = window.getSelection();
356→                    const range =
357→                      selection && selection.rangeCount > 0
358→                        ? selection.getRangeAt(0)
359→                        : null;
360→                    const selectedText = selection?.toString().trim() ?? "";
361→                    const container = event.currentTarget;
362→                    const rangeStartContainer = range?.startContainer ?? null;
363→                    const rangeEndContainer = range?.endContainer ?? null;
364→                    const hasLocalTextSelection =
365→                      Boolean(selectedText) &&
366→                      Boolean(rangeStartContainer) &&
367→                      Boolean(rangeEndContainer) &&
368→                      container.contains(rangeStartContainer) &&
369→                      container.contains(rangeEndContainer);
370→                    const anchorRect =
371→                      hasLocalTextSelection && range
372→                        ? range.getBoundingClientRect()
373→                        : container.getBoundingClientRect();
374→
375→                    emitSelection(
376→                      toViewportAnchor(anchorRect),
377→                      hasLocalTextSelection ? selectedText : blockText,
378→                    );
379→
380→                    if (selection && hasLocalTextSelection) {
381→                      selection.removeAllRanges();
382→                    }
383→                  }}
384→                  onClick={(event) => {
385→                    if (!adjustModeEnabled) {
386→                      return;
387→                    }
388→
389→                    if (
390→                      Date.now() - lastSelectionInteractionAt.current <
391→                      SELECTION_DEBOUNCE_MS
392→                    ) {
393→                      return;
394→                    }
395→
396→                    emitSelection(
397→                      toViewportAnchor(
398→                        event.currentTarget.getBoundingClientRect(),
399→                      ),
400→                      blockText,
401→                    );
402→                  }}
403→                >
404→                  <ErrorBoundary
405→                    fallback={<BlockErrorFallback blockType={block.type} />}
406→                  >
407→                    {editMode && onBlockChange ? (
408→                      <EditableBlock
409→                        block={block}
410→                        blockIndex={blockIndex}
411→                        messageId={message.id}
412→                        onBlockChange={onBlockChange}
413→                      >
414→                        <BlockRenderer block={block} effects={blockEffects} />
415→                      </EditableBlock>
416→                    ) : (
417→                      <BlockRenderer block={block} effects={blockEffects} />
418→                    )}
419→                  </ErrorBoundary>
420→                </div>
421→                {/* BlockInserter removed — insert is now in BlockToolbar */}
422→              </div>
423→              {inserts.insertAfter === "hr" && (
424→                <hr className="border-border/40" />
425→              )}
426→              {inserts.insertAfter === "spacer" && <div className="h-6" />}
427→            </React.Fragment>
428→          );
429→        })}
430→      </div>
431→    </article>
432→  );
433→});
434→
435→export function ReaderView({
436→  activeRules,
437→  adjustModeEnabled,
438→  conversation,
439→  deletedMessageIds,
440→  editMode,
441→  effectsMap,
442→  highlightedRuleId,
443→  onBlocksChange,
444→  onCopyMessage,
445→  onDeleteMessage,
446→  onDeleteRound,
447→  onRestoreMessage,
448→  onSelectBlock,
449→  selectedBlock,
450→  showDeleted,
451→}: ReaderViewProps) {
452→  const visibleMessages = useMemo(() => {
453→    if (!conversation?.messages) return [];
454→    if (!deletedMessageIds?.size) return conversation.messages;
455→    if (showDeleted) return conversation.messages;
456→    return conversation.messages.filter((m) => !deletedMessageIds.has(m.id));
457→  }, [conversation?.messages, deletedMessageIds, showDeleted]);
458→
459→  // Tracks the latest in-progress blocks per message so that consecutive edits
460→  // within the same debounce window build on top of each other rather than on
461→  // stale props (which would cause earlier edits to be overwritten).
462→  const pendingBlocksRef = useRef<Map<string, Block[]>>(new Map());
463→
464→  // When the conversation prop updates (i.e. the parent has persisted the edit
465→  // and passed the new data back down), clear any pending entries whose blocks
466→  // now match the incoming props — they are no longer "in-flight".
467→  useEffect(() => {
468→    if (!conversation) return;
469→    const pending = pendingBlocksRef.current;
470→    for (const [messageId] of pending) {
471→      const message = conversation.messages.find((m) => m.id === messageId);
472→      if (!message) {
473→        pending.delete(messageId);
474→        continue;
475→      }
476→      // If the prop blocks now reflect our last pending write, the save has
477→      // been acknowledged — remove the entry so the next edit starts fresh.
478→      const pendingBlocks = pending.get(messageId);
479→      if (
480→        pendingBlocks &&
481→        pendingBlocks.length === message.blocks.length &&
482→        pendingBlocks.every((b, i) => b === message.blocks[i])
483→      ) {
484→        pending.delete(messageId);
485→      }
486→    }
487→  }, [conversation]);
488→
489→  const highlightedBlocks = useMemo(() => {
490→    if (!highlightedRuleId || !conversation) {
491→      return new Set<string>();
492→    }
493→
494→    const rule = activeRules.find(
495→      (r) => r.id === highlightedRuleId && r.status === "active",
496→    );
497→
498→    if (!rule) {
499→      return new Set<string>();
500→    }
501→
502→    const matches = getBlocksMatchingRule(rule, conversation);
503→    return new Set(matches.map((m) => `${m.messageId}:${m.blockIndex}`));
504→  }, [highlightedRuleId, activeRules, conversation]);
505→
506→  const handleBlockChange = useCallback(
507→    (messageId: string, blockIndex: number, newBlock: Block) => {
508→      if (!onBlocksChange || !conversation) return;
509→      const message = conversation.messages.find((m) => m.id === messageId);
510→      if (!message) return;
511→
512→      // Use pending blocks as the base if present (prevents stale-closure
513→      // overwrites when the user edits multiple blocks before the debounced
514→      // save propagates updated props back down).
515→      const baseBlocks =
516→        pendingBlocksRef.current.get(messageId) ?? message.blocks;
517→
518→      const updatedBlocks = baseBlocks.map((b, i) =>
519→        i === blockIndex ? newBlock : b,
520→      );
521→
522→      pendingBlocksRef.current.set(messageId, updatedBlocks);
523→      onBlocksChange(messageId, updatedBlocks);
524→    },
525→    [onBlocksChange, conversation],
526→  );
527→
528→  if (!conversation?.messages.length) {
529→    return (
530→      <div className="rounded-2xl border border-border/80 bg-card/75 px-4 py-5 text-sm text-muted-foreground">
531→        Für diesen Import ist noch kein Transkriptinhalt verfügbar.
532→      </div>
533→    );
534→  }
535→
536→  return (
537→    <div className="space-y-3">
538→      {visibleMessages.map((message, index) => (
539→        <ReaderMessage
540→          key={message.id}
541→          adjustModeEnabled={adjustModeEnabled}
542→          editMode={editMode}
543→          effectsMap={effectsMap}
544→          highlightedBlocks={highlightedBlocks}
545→          message={message}
546→          messageIndex={index}
547→          onBlockChange={editMode ? handleBlockChange : undefined}
548→          onBlocksChange={editMode ? onBlocksChange : undefined}
549→          onCopyMessage={
550→            onCopyMessage ? () => onCopyMessage(message.id) : undefined
551→          }
552→          onSelectBlock={onSelectBlock}
553→          selectedBlock={selectedBlock}
554→          isDeleted={deletedMessageIds?.has(message.id)}
555→          onDeleteMessage={
556→            onDeleteMessage ? () => onDeleteMessage(message.id) : undefined
557→          }
558→          onDeleteRound={
559→            onDeleteRound ? () => onDeleteRound(message.id) : undefined
560→          }
561→          onRestore={
562→            onRestoreMessage
563→              ? () => {
564→                  void onRestoreMessage(message.id);
565→                }
566→              : undefined
567→          }
568→        />
569→      ))}
570→    </div>
571→  );
572→}
