 56→function getBodyInputRecord(body: Record<string, unknown>, index: number) {
 57→  const { input } = body;
 58→
 59→  if (!Array.isArray(input)) {
 60→    return null;
 61→  }
 62→
 63→  const entry = input[index];
 64→
 65→  if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
 66→    return null;
 67→  }
 68→
 69→  return entry as Record<string, unknown>;
 70→}
