 72→function getBodyInputText(body: Record<string, unknown>, index: number) {
 73→  const entry = getBodyInputRecord(body, index);
 74→  const content = entry?.content;
 75→
 76→  if (!Array.isArray(content)) {
 77→    return "";
 78→  }
 79→
 80→  const firstContentPart = content[0];
 81→
 82→  if (
 83→    !firstContentPart ||
 84→    typeof firstContentPart !== "object" ||
 85→    Array.isArray(firstContentPart)
 86→  ) {
 87→    return "";
 88→  }
 89→
 90→  return typeof firstContentPart.text === "string" ? firstContentPart.text : "";
 91→}
