214→function appendTail(tail: string[], chunk: string) {
215→  for (const line of chunk.split(/\r?\n/)) {
216→    if (!line.trim()) {
217→      continue;
218→    }
219→
220→    tail.push(line);
221→
222→    if (tail.length > 40) {
223→      tail.shift();
224→    }
225→  }
226→}
