228→function spawnManagedProcess(
229→  label: string,
230→  command: string,
231→  args: string[],
232→  extraEnv: Record<string, string>,
233→  cwd = projectRoot,
234→) {
235→  const child = spawn(command, args, {
236→    cwd,
237→    env: {
238→      ...process.env,
239→      ...extraEnv,
240→    },
241→    stdio: "pipe",
242→  });
243→  const managedChild: ManagedChild = {
244→    label,
245→    process: child,
246→    tail: [],
247→  };
248→
249→  child.stdout.setEncoding("utf8");
250→  child.stderr.setEncoding("utf8");
251→  child.stdout.on("data", (chunk: string) => {
252→    appendTail(managedChild.tail, chunk);
253→  });
254→  child.stderr.on("data", (chunk: string) => {
255→    appendTail(managedChild.tail, chunk);
256→  });
257→
258→  return managedChild;
259→}
