261→function readRequestBody(request: http.IncomingMessage) {
262→  return new Promise<string>((resolve, reject) => {
263→    const chunks: Buffer[] = [];
264→
265→    request.on("data", (chunk) => {
266→      chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(String(chunk)));
267→    });
268→    request.once("end", () => resolve(Buffer.concat(chunks).toString("utf8")));
269→    request.once("error", reject);
270→  });
271→}
