430→async function startMockOpenAiServer(): Promise<ManagedMockServer> {
431→  const server = http.createServer(async (request, response) => {
432→    if (request.method !== "POST" || request.url !== "/v1/responses") {
433→      response.writeHead(404).end("not found");
434→      return;
435→    }
436→
437→    const rawBody = await readRequestBody(request);
438→    const body = JSON.parse(rawBody) as Record<string, unknown>;
439→    const isPreviewCompilation = Boolean(
440→      (body.text as Record<string, unknown> | undefined)?.format,
441→    );
442→    const isFollowUp = typeof body.previous_response_id === "string";
443→    const payload = isPreviewCompilation
444→      ? {
445→          output_text: JSON.stringify(buildMockPreviewResponse(body)),
446→        }
447→      : isFollowUp
448→        ? buildMockFollowUpResponse(body)
449→        : buildMockChatResponse(body);
450→
451→    response.writeHead(200, {
452→      "Content-Type": "application/json",
453→    });
454→    response.end(JSON.stringify(payload));
455→  });
456→
457→  await new Promise<void>((resolve, reject) => {
458→    server.listen(mockOpenAiPort, "127.0.0.1", () => resolve());
459→    server.once("error", reject);
460→  });
461→
462→  return {
463→    close: async () => {
464→      await new Promise<void>((resolve, reject) => {
465→        server.close((error) => {
466→          if (error) {
467→            reject(error);
468→            return;
469→          }
470→
471→          resolve();
472→        });
473→      });
474→    },
475→    url: `http://127.0.0.1:${mockOpenAiPort}/v1`,
476→  };
477→}
