479→async function waitForPort(port: number, label: string) {
480→  const startedAt = Date.now();
481→
482→  while (Date.now() - startedAt < 45_000) {
483→    try {
484→      await new Promise<void>((resolve, reject) => {
485→        const socket = net.createConnection(
486→          {
487→            host: "127.0.0.1",
488→            port,
489→          },
490→          () => {
491→            socket.end();
492→            resolve();
493→          },
494→        );
495→
496→        socket.setTimeout(1_000);
497→        socket.once("timeout", () => {
498→          socket.destroy();
499→          reject(new Error("timeout"));
500→        });
501→        socket.once("error", reject);
502→      });
503→      return;
504→    } catch {
505→      // Retry until timeout.
506→    }
507→
508→    await delay(500);
509→  }
510→
511→  throw new Error(`Timed out while waiting for ${label} on port ${port}.`);
512→}
