524→async function stopManagedProcess(child: ManagedChild) {
525→  if (child.process.exitCode !== null || child.process.killed) {
526→    return;
527→  }
528→
529→  child.process.kill("SIGTERM");
530→  await Promise.race([
531→    new Promise<void>((resolve) => {
532→      child.process.once("exit", () => resolve());
533→    }),
534→    delay(5_000),
535→  ]);
536→
537→  if (child.process.exitCode === null && !child.process.killed) {
538→    child.process.kill("SIGKILL");
539→  }
540→}
