  1→import type { Block } from "@chat-exporter/shared";
  2→import {
  3→  ArrowDown,
  4→  ArrowUp,
  5→  Code,
  6→  Copy,
  7→  Heading2,
  8→  Heading3,
  9→  List,
 10→  Pilcrow,
 11→  Plus,
 12→  Quote,
 13→  Table,
 14→  Trash2,
 15→} from "lucide-react";
 16→import { useCallback, useState } from "react";
 17→
 18→import {
 19→  DropdownMenu,
 20→  DropdownMenuContent,
 21→  DropdownMenuItem,
 22→  DropdownMenuLabel,
 23→  DropdownMenuSeparator,
 24→  DropdownMenuTrigger,
 25→} from "@/components/ui/dropdown-menu";
 26→
 27→// ---------------------------------------------------------------------------
 28→// Pure utility: extract text from any block type
 29→// ---------------------------------------------------------------------------
 30→
 31→export function getBlockText(block: Block): string {
 32→  switch (block.type) {
 33→    case "paragraph":
 34→    case "heading":
 35→    case "quote":
 36→    case "code":
 37→      return block.text;
 38→    case "list":
 39→      return block.items.join("\n");
 40→    case "table": {
 41→      const headerLine = block.headers.join(" | ");
 42→      const rows = block.rows.map((row) => row.join(" | ")).join("\n");
 43→      return rows ? `${headerLine}\n${rows}` : headerLine;
 44→    }
 45→  }
 46→}
 47→
 48→// ---------------------------------------------------------------------------
 49→// Pure utility: convert a block to a different type
 50→// ---------------------------------------------------------------------------
 51→
 52→export type ConvertibleBlockType = "paragraph" | "heading" | "quote" | "list";
 53→
 54→export function convertBlockType(
 55→  block: Block,
 56→  targetType: ConvertibleBlockType,
 57→): Block {
 58→  const text = getBlockText(block);
 59→  switch (targetType) {
 60→    case "paragraph":
 61→      return { type: "paragraph", text };
 62→    case "heading":
 63→      return { type: "heading", level: 2, text };
 64→    case "quote":
 65→      return { type: "quote", text };
 66→    case "list":
 67→      return { type: "list", ordered: false, items: [text] };
 68→  }
 69→}
 70→
 71→// ---------------------------------------------------------------------------
 72→// Insert-block menu items
 73→// ---------------------------------------------------------------------------
 74→
 75→const INSERT_BLOCK_ITEMS = [
