102→
103→export interface BlockToolbarProps {
104→  block: Block;
105→  blockIndex: number;
106→  totalBlocks: number;
107→  onDelete: (blockIndex: number) => void;
108→  onDuplicate: (blockIndex: number) => void;
109→  onInsertBlock: (blockIndex: number, block: Block) => void;
110→  onMenuOpenChange?: (open: boolean) => void;
111→  onMoveUp: (blockIndex: number) => void;
112→  onMoveDown: (blockIndex: number) => void;
113→}
114→
115→export function BlockToolbar({
116→  block,
117→  blockIndex,
118→  totalBlocks,
119→  onDelete,
120→  onDuplicate,
121→  onInsertBlock,
122→  onMenuOpenChange,
123→  onMoveUp,
124→  onMoveDown,
125→}: BlockToolbarProps) {
126→  const isFirst = blockIndex === 0;
127→  const isLast = blockIndex === totalBlocks - 1;
128→
129→  // Track how many dropdowns are open so the parent can prevent unmounting
130→  const [openCount, setOpenCount] = useState(0);
131→  const handleDropdownOpenChange = useCallback(
132→    (open: boolean) => {
133→      setOpenCount((c) => {
134→        const next = c + (open ? 1 : -1);
135→        onMenuOpenChange?.(next > 0);
136→        return next;
137→      });
138→    },
139→    [onMenuOpenChange],
140→  );
141→
142→  const handleInsertSelect = useCallback(
143→    (key: string) => {
144→      const template = BLOCK_DEFAULTS[key];
145→      if (template) {
146→        onInsertBlock(blockIndex + 1, { ...template } as Block);
147→      }
148→    },
149→    [blockIndex, onInsertBlock],
150→  );
151→
152→  return (
153→    <div className="absolute -top-8 left-0 z-10 flex items-center gap-0.5 rounded-lg border border-border/60 bg-background px-1 py-0.5 shadow-sm">
154→      {/* Insert block dropdown */}
155→      <DropdownMenu onOpenChange={handleDropdownOpenChange}>
156→        <DropdownMenuTrigger asChild>
157→          <button
158→            type="button"
159→            className="flex h-6 w-6 items-center justify-center rounded text-muted-foreground hover:bg-secondary hover:text-foreground transition-colors"
160→            aria-label="Block einfügen"
161→          >
162→            <Plus className="h-3.5 w-3.5" />
163→          </button>
164→        </DropdownMenuTrigger>
165→        <DropdownMenuContent align="start" className="w-44">
166→          <DropdownMenuLabel className="text-xs">Einfügen nach</DropdownMenuLabel>
167→          <DropdownMenuSeparator />
168→          {INSERT_BLOCK_ITEMS.map(({ key, label, icon: Icon }) => (
169→            <DropdownMenuItem key={key} onSelect={() => handleInsertSelect(key)}>
170→              <Icon className="h-4 w-4" />
171→              <span>{label}</span>
172→            </DropdownMenuItem>
173→          ))}
174→        </DropdownMenuContent>
175→      </DropdownMenu>
176→
177→      {/* Move up */}
178→      <button
179→        type="button"
180→        className="flex h-6 w-6 items-center justify-center rounded text-muted-foreground hover:bg-secondary hover:text-foreground transition-colors disabled:opacity-30 disabled:pointer-events-none"
181→        aria-label="Block nach oben"
182→        disabled={isFirst}
183→        onClick={() => onMoveUp(blockIndex)}
184→      >
185→        <ArrowUp className="h-3.5 w-3.5" />
186→      </button>
187→
188→      {/* Move down */}
189→      <button
190→        type="button"
191→        className="flex h-6 w-6 items-center justify-center rounded text-muted-foreground hover:bg-secondary hover:text-foreground transition-colors disabled:opacity-30 disabled:pointer-events-none"
192→        aria-label="Block nach unten"
193→        disabled={isLast}
194→        onClick={() => onMoveDown(blockIndex)}
195→      >
196→        <ArrowDown className="h-3.5 w-3.5" />
197→      </button>
198→
199→      {/* Duplicate */}
200→      <button
201→        type="button"
202→        className="flex h-6 w-6 items-center justify-center rounded text-muted-foreground hover:bg-secondary hover:text-foreground transition-colors"
203→        aria-label="Block duplizieren"
204→        onClick={() => onDuplicate(blockIndex)}
205→      >
206→        <Copy className="h-3.5 w-3.5" />
207→      </button>
208→
209→      {/* Delete */}
210→      <button
211→        type="button"
212→        className="flex h-6 w-6 items-center justify-center rounded text-muted-foreground hover:bg-red-100 hover:text-red-600 transition-colors"
213→        aria-label="Block löschen"
214→        onClick={() => onDelete(blockIndex)}
215→      >
216→        <Trash2 className="h-3.5 w-3.5" />
217→      </button>
218→    </div>
219→  );
220→}
