 74→// ---------------------------------------------------------------------------
 75→// Helpers — build DOM structures for list/table blur tests
 76→// ---------------------------------------------------------------------------
 77→
 78→function setListDom(element: HTMLElement, items: string[]) {
 79→  while (element.firstChild) element.removeChild(element.firstChild);
 80→  const ul = document.createElement("ul");
 81→  for (const item of items) {
 82→    const li = document.createElement("li");
 83→    li.textContent = item;
 84→    ul.appendChild(li);
 85→  }
 86→  element.appendChild(ul);
 87→}
 88→
 89→/**
 90→ * Builds the DOM structure that BlockRenderer produces for a code block:
 91→ *   <div>
 92→ *     <p>{language}</p>
 93→ *     <pre><code>{code}</code></pre>
 94→ *   </div>
 95→ */
 96→function setCodeBlockDom(element: HTMLElement, language: string, code: string) {
 97→  while (element.firstChild) element.removeChild(element.firstChild);
 98→  const wrapper = document.createElement("div");
 99→  const langLabel = document.createElement("p");
100→  langLabel.textContent = language;
101→  wrapper.appendChild(langLabel);
102→  const pre = document.createElement("pre");
103→  const codeEl = document.createElement("code");
104→  codeEl.textContent = code;
105→  pre.appendChild(codeEl);
106→  wrapper.appendChild(pre);
107→  element.appendChild(wrapper);
108→}
109→
110→function setTableDom(
111→  element: HTMLElement,
112→  headers: string[],
113→  rows: string[][],
114→) {
115→  while (element.firstChild) element.removeChild(element.firstChild);
116→  const table = document.createElement("table");
117→  const thead = document.createElement("thead");
118→  const headRow = document.createElement("tr");
119→  for (const h of headers) {
120→    const th = document.createElement("th");
121→    th.textContent = h;
122→    headRow.appendChild(th);
123→  }
124→  thead.appendChild(headRow);
125→  table.appendChild(thead);
126→
127→  const tbody = document.createElement("tbody");
128→  for (const row of rows) {
129→    const tr = document.createElement("tr");
130→    for (const cell of row) {
131→      const td = document.createElement("td");
132→      td.textContent = cell;
133→      tr.appendChild(td);
134→    }
135→    tbody.appendChild(tr);
136→  }
137→  table.appendChild(tbody);
138→  element.appendChild(table);
139→}
