  1→import type { Block } from "@chat-exporter/shared";
  2→import React, { useCallback, useRef } from "react";
  3→import { cn } from "@/lib/utils";
  4→
  5→/**
  6→ * Renders children only on initial mount — prevents React from reconciling
  7→ * DOM nodes that the browser's contentEditable engine has modified.
  8→ */
  9→const FrozenChildren = React.memo(
 10→  ({ children }: { children: React.ReactNode }) => <>{children}</>,
 11→  () => true,
 12→);
 13→
 14→interface EditableBlockProps {
 15→  block: Block;
 16→  blockIndex: number;
 17→  messageId: string;
 18→  onBlockChange: (
 19→    messageId: string,
 20→    blockIndex: number,
 21→    newBlock: Block,
 22→  ) => void;
 23→  children: React.ReactNode;
 24→}
 25→
 26→/**
 27→ * Read the DOM content of the editable element and construct a new Block
 28→ * that matches the original block's type, preserving type-specific fields
 29→ * (e.g. heading level, code language, list ordered flag).
 30→ */
 31→function readBlockFromDom(element: HTMLElement, original: Block): Block {
 32→  switch (original.type) {
 33→    case "paragraph":
 34→      return { type: "paragraph", text: element.textContent ?? "" };
 35→
 36→    case "heading":
 37→      return {
 38→        type: "heading",
 39→        level: original.level,
 40→        text: element.textContent ?? "",
 41→      };
 42→
 43→    case "quote":
 44→      return { type: "quote", text: element.textContent ?? "" };
 45→
 46→    case "code": {
 47→      const codeEl = element.querySelector("pre code");
 48→      return {
 49→        type: "code",
 50→        language: original.language,
 51→        text: codeEl ? (codeEl.textContent ?? "") : (element.textContent ?? ""),
 52→      };
 53→    }
 54→
 55→    case "list": {
 56→      const listItems = element.querySelectorAll("li");
 57→      const items = Array.from(listItems).map((li) => li.textContent ?? "");
 58→      return {
 59→        type: "list",
 60→        ordered: original.ordered,
 61→        items: items.length > 0 ? items : [element.textContent ?? ""],
 62→      };
 63→    }
 64→
 65→    case "table": {
 66→      const thElements = element.querySelectorAll("th");
 67→      const headers = Array.from(thElements).map((th) => th.textContent ?? "");
 68→
 69→      const bodyRows = element.querySelectorAll("tbody tr");
 70→      const rows = Array.from(bodyRows).map((tr) => {
 71→        const cells = tr.querySelectorAll("td");
 72→        return Array.from(cells).map((td) => td.textContent ?? "");
 73→      });
 74→
 75→      return { type: "table", headers, rows };
 76→    }
 77→
 78→    default:
 79→      return original;
 80→  }
 81→}
 82→
 83→export function EditableBlock({
 84→  block,
 85→  blockIndex,
 86→  messageId,
 87→  onBlockChange,
 88→  children,
 89→}: EditableBlockProps) {
 90→  const ref = useRef<HTMLDivElement>(null);
 91→
 92→  const handleBlur = useCallback(() => {
 93→    const element = ref.current;
 94→    if (!element) return;
 95→
 96→    const newBlock = readBlockFromDom(element, block);
 97→    onBlockChange(messageId, blockIndex, newBlock);
 98→  }, [block, blockIndex, messageId, onBlockChange]);
 99→
100→  const handleKeyDown = useCallback(
101→    (event: React.KeyboardEvent<HTMLDivElement>) => {
102→      if (event.key === "Escape") {
103→        event.currentTarget.blur();
104→      }
105→    },
106→    [],
107→  );
108→
109→  const handlePaste = useCallback(
110→    (event: React.ClipboardEvent<HTMLDivElement>) => {
111→      event.preventDefault();
112→      const plainText = event.clipboardData.getData("text/plain");
113→      const selection = window.getSelection();
114→      if (selection && selection.rangeCount > 0) {
115→        const range = selection.getRangeAt(0);
116→        range.deleteContents();
117→        range.insertNode(document.createTextNode(plainText));
118→        range.collapse(false);
119→      }
120→    },
121→    [],
122→  );
123→
124→  const isCodeBlock = block.type === "code";
125→
126→  return (
127→    /* biome-ignore lint/a11y/useSemanticElements: contentEditable div wraps arbitrary block content, not a simple text input */
128→    <div
129→      ref={ref}
130→      role="textbox"
131→      tabIndex={0}
132→      data-testid="editable-block"
133→      contentEditable
134→      suppressContentEditableWarning
135→      onBlur={handleBlur}
136→      onKeyDown={handleKeyDown}
137→      onPaste={handlePaste}
138→      className={cn(
139→        "outline-none rounded-md ring-0 focus:ring-1 focus:ring-blue-300 transition-shadow",
140→        isCodeBlock && "whitespace-pre-wrap",
141→      )}
142→    >
143→      <FrozenChildren>{children}</FrozenChildren>
144→    </div>
145→  );
146→}
