  1→import type { Block, Conversation } from "@chat-exporter/shared";
  2→import { renderHook } from "@testing-library/react";
  3→import { describe, expect, test } from "vitest";
  4→
  5→import { useResolvedConversation } from "./use-resolved-conversation";
  6→
  7→function createConversation(
  8→  messages: Array<{ id: string; role: "user" | "assistant"; blocks: Block[] }>,
  9→): Conversation {
 10→  return {
 11→    id: "conv-1",
 12→    title: "Test Conversation",
 13→    source: { url: "https://example.com/chat", platform: "chatgpt" },
 14→    messages,
 15→  };
 16→}
 17→
 18→function textBlock(text: string): Block {
 19→  return { type: "paragraph", text };
 20→}
 21→
 22→describe("useResolvedConversation", () => {
 23→  test("returns original messages when editedMessagesMap is empty", () => {
 24→    const conversation = createConversation([
 25→      { id: "m1", role: "user", blocks: [textBlock("Hello")] },
 26→      { id: "m2", role: "assistant", blocks: [textBlock("Hi there")] },
 27→    ]);
 28→
 29→    const { result } = renderHook(() =>
 30→      useResolvedConversation(conversation, new Map()),
 31→    );
 32→
 33→    expect(result.current).toHaveLength(2);
 34→    expect(result.current.at(0)?.blocks).toEqual([textBlock("Hello")]);
 35→    expect(result.current.at(1)?.blocks).toEqual([textBlock("Hi there")]);
 36→  });
 37→
 38→  test("marks non-edited messages with isEdited: false", () => {
 39→    const conversation = createConversation([
 40→      { id: "m1", role: "user", blocks: [textBlock("Hello")] },
 41→    ]);
 42→
 43→    const { result } = renderHook(() =>
 44→      useResolvedConversation(conversation, new Map()),
 45→    );
 46→
 47→    expect(result.current.at(0)?.isEdited).toBe(false);
 48→  });
 49→
 50→  test("replaces blocks for edited messages", () => {
 51→    const conversation = createConversation([
 52→      { id: "m1", role: "user", blocks: [textBlock("Original")] },
 53→      { id: "m2", role: "assistant", blocks: [textBlock("Original reply")] },
 54→    ]);
 55→    const editedBlocks: Block[] = [textBlock("Edited content")];
 56→    const editsMap = new Map<string, Block[]>([["m1", editedBlocks]]);
 57→
 58→    const { result } = renderHook(() =>
 59→      useResolvedConversation(conversation, editsMap),
 60→    );
 61→
 62→    expect(result.current.at(0)?.blocks).toEqual([textBlock("Edited content")]);
 63→    expect(result.current.at(1)?.blocks).toEqual([textBlock("Original reply")]);
 64→  });
