 66→  test("marks edited messages with isEdited: true", () => {
 67→    const conversation = createConversation([
 68→      { id: "m1", role: "user", blocks: [textBlock("Original")] },
 69→      { id: "m2", role: "assistant", blocks: [textBlock("Reply")] },
 70→    ]);
 71→    const editsMap = new Map<string, Block[]>([["m1", [textBlock("Edited")]]]);
 72→
 73→    const { result } = renderHook(() =>
 74→      useResolvedConversation(conversation, editsMap),
 75→    );
 76→
 77→    expect(result.current.at(0)?.isEdited).toBe(true);
 78→    expect(result.current.at(1)?.isEdited).toBe(false);
 79→  });
 80→
 81→  test("handles undefined conversation gracefully", () => {
 82→    const { result } = renderHook(() =>
 83→      useResolvedConversation(undefined, new Map()),
 84→    );
 85→
 86→    expect(result.current).toEqual([]);
