  1→import type { Block, Conversation, FormatRule } from "@chat-exporter/shared";
  2→import { describe, expect, test, vi } from "vitest";
  3→
  4→vi.mock("@/lib/utils", () => ({
  5→  cn: (...args: unknown[]) => args.filter(Boolean).join(" "),
  6→}));
  7→
  8→vi.mock("./reader-block-render", () => ({
  9→  blockToPlainText: (block: Block) => {
 10→    switch (block.type) {
 11→      case "paragraph":
 12→      case "heading":
 13→      case "quote":
 14→      case "code":
 15→        return block.text;
 16→      case "list":
 17→        return block.items.join("\n");
 18→      case "table":
 19→        return [
 20→          block.headers.join(" | "),
 21→          ...block.rows.map((row) => row.join(" | ")),
 22→        ].join("\n");
 23→    }
 24→  },
 25→}));
 26→
 27→import type { ReaderMatchContext } from "./rule-matching";
 28→import { getBlocksMatchingRule, matchesReaderRule } from "./rule-matching";
 29→
 30→// ---------------------------------------------------------------------------
 31→// Factories
 32→// ---------------------------------------------------------------------------
 33→
 34→function createRule(overrides?: Partial<FormatRule>): FormatRule {
 35→  return {
 36→    id: "rule-1",
 37→    importId: null,
 38→    targetFormat: "reader",
 39→    kind: "inline_semantics",
 40→    scope: "import_local",
 41→    status: "active",
 42→    selector: { strategy: "compound" },
 43→    instruction: "compound rule",
 44→    compiledRule: {
 45→      type: "custom_style",
 46→      textTransform: "bold_prefix_before_colon",
 47→    },
 48→    sourceSessionId: undefined,
 49→    createdAt: "2026-01-01T00:00:00Z",
 50→    updatedAt: "2026-01-01T00:00:00Z",
 51→    ...overrides,
 52→  };
 53→}
 54→
 55→function createConversation(overrides?: Partial<Conversation>): Conversation {
 56→  return {
 57→    id: "conv-1",
 58→    title: "Test Conversation",
 59→    source: { url: "https://example.com/chat", platform: "chatgpt" },
 60→    messages: [
 61→      {
 62→        id: "msg-1",
 63→        role: "assistant",
 64→        blocks: [
 65→          { type: "heading", text: "Title", level: 1 },
 66→          { type: "paragraph", text: "Hello world" },
 67→        ],
 68→      },
 69→    ],
 70→    ...overrides,
 71→  };
 72→}
 73→
 74→function createContext(
 75→  overrides?: Partial<ReaderMatchContext>,
 76→): ReaderMatchContext {
 77→  return {
 78→    messageRole: "assistant",
 79→    blocks: [
 80→      { type: "heading", text: "Title", level: 1 },
 81→      { type: "paragraph", text: "Hello world" },
 82→      { type: "code", text: "const x = 1", language: "ts" },
 83→    ],
 84→    ...overrides,
 85→  };
 86→}
 87→
 88→// ---------------------------------------------------------------------------
 89→// Tests — matchesReaderRule compound strategy
 90→// ---------------------------------------------------------------------------
 91→
 92→describe("matchesReaderRule — compound strategy", () => {
 93→  // Block-Filter
 94→  test("matches by blockType alone", () => {
 95→    const rule = createRule({
 96→      selector: { strategy: "compound", blockType: "paragraph" },
 97→    });
 98→
 99→    const result = matchesReaderRule(rule, "msg-1", 0, "paragraph", "text");
100→
101→    expect(result).toBe(true);
102→  });
103→
104→  test("matches by messageRole alone", () => {
105→    const rule = createRule({
106→      selector: { strategy: "compound", messageRole: "assistant" },
107→    });
108→    const ctx = createContext({ messageRole: "assistant" });
109→
110→    const result = matchesReaderRule(
111→      rule,
112→      "msg-1",
113→      0,
114→      "paragraph",
115→      "text",
116→      ctx,
117→    );
118→
119→    expect(result).toBe(true);
120→  });
121→
122→  test("matches by headingLevel alone", () => {
123→    const rule = createRule({
124→      selector: { strategy: "compound", headingLevel: 2 },
125→    });
126→    const blocks: Block[] = [{ type: "heading", text: "Sub", level: 2 }];
127→    const ctx = createContext({ blocks });
128→
129→    const result = matchesReaderRule(rule, "msg-1", 0, "heading", "Sub", ctx);
130→
131→    expect(result).toBe(true);
132→  });
133→
134→  test("matches by position: first", () => {
135→    const rule = createRule({
136→      selector: { strategy: "compound", position: "first" },
137→    });
138→    const ctx = createContext();
139→
140→    const result = matchesReaderRule(rule, "msg-1", 0, "heading", "Title", ctx);
141→
142→    expect(result).toBe(true);
143→  });
144→
145→  test("matches by position: last", () => {
146→    const rule = createRule({
147→      selector: { strategy: "compound", position: "last" },
148→    });
149→    const ctx = createContext(); // 3 blocks
150→
151→    const result = matchesReaderRule(
152→      rule,
153→      "msg-1",
154→      2,
155→      "code",
156→      "const x = 1",
157→      ctx,
158→    );
159→
160→    expect(result).toBe(true);
161→  });
162→
163→  test("matches by textPattern (regex)", () => {
164→    const rule = createRule({
165→      selector: { strategy: "compound", textPattern: "^Hello" },
166→    });
167→
168→    const result = matchesReaderRule(
