171→      0,
172→      "paragraph",
173→      "Hello world",
174→    );
175→
176→    expect(result).toBe(true);
177→  });
178→
179→  // AND-Verknüpfung
180→  test("AND: blockType + messageRole — both match → true", () => {
181→    const rule = createRule({
182→      selector: {
183→        strategy: "compound",
184→        blockType: "paragraph",
185→        messageRole: "assistant",
186→      },
187→    });
188→    const ctx = createContext({ messageRole: "assistant" });
189→
190→    const result = matchesReaderRule(
191→      rule,
192→      "msg-1",
193→      1,
194→      "paragraph",
195→      "Hello world",
196→      ctx,
197→    );
198→
199→    expect(result).toBe(true);
200→  });
201→
202→  test("AND: blockType + messageRole — role mismatch → false", () => {
203→    const rule = createRule({
204→      selector: {
205→        strategy: "compound",
206→        blockType: "paragraph",
207→        messageRole: "user",
208→      },
209→    });
210→    const ctx = createContext({ messageRole: "assistant" });
211→
212→    const result = matchesReaderRule(
213→      rule,
214→      "msg-1",
215→      1,
216→      "paragraph",
217→      "Hello world",
218→      ctx,
219→    );
220→
221→    expect(result).toBe(false);
222→  });
223→
224→  test("AND: blockType + textPattern — pattern mismatch → false", () => {
225→    const rule = createRule({
226→      selector: {
227→        strategy: "compound",
228→        blockType: "paragraph",
