249→        blockType: "paragraph",
250→        context: { previousSibling: { blockType: "heading" } },
251→      },
252→    });
253→    const ctx = createContext(); // [heading, paragraph, code]
254→
255→    const result = matchesReaderRule(
256→      rule,
257→      "msg-1",
258→      1,
259→      "paragraph",
260→      "Hello world",
261→      ctx,
262→    );
263→
264→    expect(result).toBe(true);
265→  });
