271→        blockType: "paragraph",
272→        context: { previousSibling: { blockType: "code" } },
273→      },
274→    });
275→    const ctx = createContext(); // [heading, paragraph, code]
276→
277→    const result = matchesReaderRule(
278→      rule,
279→      "msg-1",
280→      1,
281→      "paragraph",
282→      "Hello world",
283→      ctx,
284→    );
285→
286→    expect(result).toBe(false);
287→  });
288→
289→  test("context: previousSibling headingLevel matches", () => {
290→    const rule = createRule({
291→      selector: {
292→        strategy: "compound",
293→        context: { previousSibling: { headingLevel: 1 } },
294→      },
295→    });
296→    const ctx = createContext(); // [heading(level:1), paragraph, code]
297→
298→    const result = matchesReaderRule(
