  --muted-fg: hsl(194 12% 42%);
  --primary: hsl(177 70% 26%);
  --accent: hsl(28 95% 58%);
  --border: hsl(192 24% 84%);
  --radius: 1.15rem;
}

*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  color-scheme: light;
}

body {
  font-family: "IBM Plex Sans", "Avenir Next", "Segoe UI", sans-serif;
  color: var(--foreground);
  background:
    radial-gradient(circle at top left, hsl(28 95% 58% / 0.16), transparent 30%),
    radial-gradient(circle at 90% 10%, hsl(177 70% 26% / 0.16), transparent 24%),
    linear-gradient(180deg, var(--background), hsl(35 35% 94%));
  min-height: 100vh;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  line-height: 1.5;
}

code, pre {
  font-family: "JetBrains Mono", "SFMono-Regular", "Menlo", monospace;
}

.container {
  max-width: 48rem;
  margin: 0 auto;
  padding: 2rem 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.message {
  border-radius: 1.55rem;
  border: 1px solid var(--border);
  padding: 1.25rem 1.25rem;
}

.msg-assistant {
  background: hsl(0 0% 100% / 0.92);
}

.msg-user {
  background: hsl(38 40% 92% / 0.3);
}

.msg-header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  margin-bottom: 1rem;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.18em;
  color: var(--muted-fg);
}

.msg-blocks {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.block-wrapper {
  border-radius: calc(var(--radius) + 0.5rem);
  padding: 0.5rem 0.75rem;
}

.block-paragraph {
  font-size: 0.875rem;
  line-height: 1.75rem;
  color: hsl(195 28% 11% / 0.9);
}

.block-heading {
  font-weight: 600;
  color: var(--foreground);
}

h1.block-heading { font-size: 1.5rem; }
h2.block-heading { font-size: 1.25rem; }
h3.block-heading { font-size: 1.125rem; }
h4.block-heading { font-size: 1rem; }
h5.block-heading { font-size: 0.875rem; }
h6.block-heading { font-size: 0.8rem; }

.block-list {
  list-style: disc;
  padding-left: 1.25rem;
  font-size: 0.875rem;
  line-height: 1.75rem;
  color: hsl(195 28% 11% / 0.9);
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.block-quote {
  border-left: 2px solid var(--accent);
  padding-left: 1rem;
  font-size: 0.875rem;
  font-style: italic;
  line-height: 1.75rem;
  color: hsl(195 28% 11% / 0.8);
}

.block-code {
  border-radius: calc(var(--radius) + 0.5rem);
  border: 1px solid var(--border);
  background: hsl(240 6% 7%);
  padding: 1rem;
  font-size: 0.875rem;
  color: hsl(0 0% 96%);
}

.code-lang {
  margin-bottom: 0.75rem;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.22em;
  color: hsl(240 5% 65%);
}

.block-code pre {
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-word;
}

.block-table-wrap {
  overflow-x: auto;
  border-radius: calc(var(--radius) + 0.5rem);
  border: 1px solid var(--border);
}

.block-table {
  min-width: 100%;
  text-align: left;
  font-size: 0.875rem;
  border-collapse: collapse;
}

.block-table thead {
  background: hsl(38 40% 92% / 0.7);
