 43→describe("buildReaderHtml style attribute XSS prevention", () => {
 44→  test("escapes double quotes in containerStyle values to prevent attribute breakout", () => {
 45→    // Arrange
 46→    const maliciousEffect: RuleEffect = {
 47→      type: "custom_style",
 48→      containerStyle: {
 49→        color: '"; onclick="alert(1)',
 50→      },
