 55→    // Act
 56→    const html = buildReaderHtml(conversation, effectsMap);
 57→
 58→    // Assert — the raw attack string must not appear verbatim in the output
 59→    expect(html).not.toContain('" onclick="alert(1)');
 60→    // The double-quote must be HTML-encoded
 61→    expect(html).toContain("&quot;");
 62→  });
 63→
 64→  test("escapes angle brackets in containerStyle values to prevent tag injection", () => {
 65→    // Arrange
 66→    const maliciousEffect: RuleEffect = {
 67→      type: "custom_style",
 68→      containerStyle: {
 69→        background: "red</style><script>alert(1)</script>",
 70→      },
 71→    };
 72→    const effectsMap = makeEffectsMap("msg-1", 0, [maliciousEffect]);
 73→    const conversation = makeConversation();
 74→
 75→    // Act
 76→    const html = buildReaderHtml(conversation, effectsMap);
 77→
 78→    // Assert — raw < and > must not appear inside the style attribute value
 79→    expect(html).not.toContain("</style><script>");
 80→    expect(html).toContain("&lt;");
 81→    expect(html).toContain("&gt;");
 82→  });
