 94→    const conversation = makeConversation();
 95→
 96→    // Act
 97→    const html = buildReaderHtml(conversation, effectsMap);
 98→
 99→    // Assert — safe CSS values must survive unchanged
100→    expect(html).toContain("font-size: 1.25rem");
101→    expect(html).toContain("background-color: hsl(28 95% 58% / 0.12)");
102→  });
